        if pos < s.len() && s[pos] == b'+' {
            pos += 1;
        }
        false
    };
    // C: if (!isalnum((unsigned char)*s)) return NULL; /* no digit? */
    if pos >= s.len() || !s[pos].is_ascii_alphanumeric() {
        return None;
    }
    let mut n: u64 = 0u64;
    // C: do { ... } while (isalnum((unsigned char)*s));
    loop {
        let byte = s[pos];
        let digit = if byte.is_ascii_digit() {
            (byte - b'0') as u32
