        let bytes: Vec<u8> = state
            .to_lua_string_bytes(1)
            .map(|b| b.to_vec())
            .unwrap_or_default();
        // C: luaL_argcheck(L, 2 <= base && base <= 36, 2, "base out of range");
        if !(2..=36).contains(&base) {
            return Err(LuaError::arg_error(2, "base out of range"));
