/// C: `static int luaB_type(lua_State *L)`
pub(crate) fn type_fn(state: &mut LuaState) -> Result<usize, LuaError> {
    // C: int t = lua_type(L, 1);
    let t = state.type_at(1);
    // C: luaL_argcheck(L, t != LUA_TNONE, 1, "value expected");
    if t == LuaType::None {
