    // C: lua_pushvalue(L, -1); lua_setfield(L, -2, LUA_GNAME);
    state.push_copy(-1)?;
    state.set_field(-2, LUA_GNAME)?;
    // C: lua_pushliteral(L, LUA_VERSION); lua_setfield(L, -2, "_VERSION");
    state.push_string(LUA_VERSION_STR)?;
    state.set_field(-2, b"_VERSION")?;
    Ok(1)
}

